#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[100005];
        scanf("%s", S);
        int N = strlen(S);
        int min = N*(N-1)/2;
        for (int i = 0; i < N; i++) {
            for (char c = 'a'; c <= 'z'; c++) {
                char temp = S[i];
                S[i] = c;
                int Y = 0;
                for (int j = 0; j < N; j++) {
                    for (int k = j+1; k < N; k++) {
                        if (S[j] < S[k]) Y++;
                    }
                }
                int X = (c != temp) ? abs(c - temp) : 0;
                min = (X + Y < min) ? X + Y : min;
                S[i] = temp;
            }
        }
        printf("%d\n", min);
    }
    return 0;
}

