import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        sc.nextLine();
        while (T-- > 0) {
            String S = sc.nextLine();
            int N = S.length();
            int min = N*(N-1)/2;
            for (int i = 0; i < N; i++) {
                for (char c = 'a'; c <= 'z'; c++) {
                    char[] temp = S.toCharArray();
                    temp[i] = c;
                    String tempS = new String(temp);
                    int Y = 0;
                    for (int j = 0; j < N; j++) {
                        for (int k = j+1; k < N; k++) {
                            if (tempS.charAt(j) < tempS.charAt(k)) Y++;
                        }
                    }
                    int X = (c != S.charAt(i)) ? Math.abs(c - S.charAt(i)) : 0;
                    min = (X + Y < min) ? X + Y : min;
                }
            }
            System.out.println(min);
        }
    }
}

