const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const S = readline();
    const N = S.length;
    let min = N*(N-1)/2;
    for (let j = 0; j < N; j++) {
        for (let c = 'a'.charCodeAt(0); c <= 'z'.charCodeAt(0); c++) {
            const temp = S.split('');
            temp[j] = String.fromCharCode(c);
            let Y = 0;
            for (let k = 0; k < N; k++) {
                for (let l = k+1; l < N; l++) {
                    if (temp[k] < temp[l]) Y++;
                }
            }
            const X = (c !== S.charCodeAt(j)) ? Math.abs(c - S.charCodeAt(j)) : 0;
            min = Math.min(min, X + Y);
        }
    }
    console.log(min);
}

